import classes from "./MainHeaderTab.module.css";

const MainHeaderTab = (props) => {
  const setTabHandler = (title) => {
    props.setTabHandler(title);
  };

  console.log(props.selectedTab);

  return (
    <div className={classes["tab"]} onClick={props.onClickHandler}>
      {props.title}
    </div>
  );
};

export default MainHeaderTab;
